import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';

export default function TaskStatus() {
  const { id } = useParams();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [task, setTask] = useState(null);
  const [loading, setLoading] = useState(true);
  const [completing, setCompleting] = useState(false);

  useEffect(() => {
    api.get(`/tasks/${id}`)
      .then(res => setTask(res.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [id]);

  const handleComplete = async () => {
    setCompleting(true);
    try {
      await api.post(`/tasks/${id}/complete`);
      navigate(`/tasks/${id}/rate`);
    } catch (err) {
      alert(err.response?.data?.error || 'Ошибка');
    } finally {
      setCompleting(false);
    }
  };

  if (loading) return <div className="app-container"><div className="loading"><div className="spinner" /></div></div>;
  if (!task) return <div className="app-container" style={{ padding: 20 }}><div className="error-msg">Задача не найдена</div></div>;

  const isOwner = user?.id === task.customer_id;

  return (
    <div className="app-container">
      <div className="page-header">
        <button className="back-btn" onClick={() => navigate(-1)}>← Назад</button>
        <span className="page-title">Task Status</span>
      </div>

      <div style={{ padding: '24px 20px' }}>
        <h2 style={{ fontSize: 20, fontWeight: 800, textAlign: 'center', marginBottom: 16 }}>
          {task.title}
        </h2>

        {/* Status badge */}
        <div style={{ textAlign: 'center', marginBottom: 24 }}>
          <span className={`badge badge-${task.status}`} style={{ fontSize: 14, padding: '6px 16px' }}>
            {task.status === 'open' ? '🟢 Открыта' : task.status === 'in_progress' ? '🟡 В работе' : '✅ Завершена'}
          </span>
        </div>

        {/* Helper info */}
        {task.helper_id && (
          <div className="card" style={{ marginBottom: 16 }}>
            <div style={{ fontSize: 12, color: 'var(--text-muted)', fontWeight: 600, marginBottom: 8, textTransform: 'uppercase' }}>
              Helper
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
              <div style={{
                width: 48, height: 48, borderRadius: '50%', background: '#e5e7eb',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 20, fontWeight: 700
              }}>
                {task.helper_name?.[0]?.toUpperCase()}
              </div>
              <div>
                <div style={{ fontWeight: 700 }}>{task.helper_name}</div>
                <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>⭐ {task.helper_rating || '—'}</div>
              </div>
            </div>
          </div>
        )}

        {/* Time */}
        <div className="card" style={{ marginBottom: 16 }}>
          <div style={{ display: 'flex', flex: 'column', gap: 12 }}>
            <div>
              <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: 4 }}>TIME</div>
              <div style={{ fontWeight: 600 }}>
                {task.created_at
                  ? new Date(task.created_at).toLocaleString('ru-RU', { day: 'numeric', month: 'long', hour: '2-digit', minute: '2-digit' })
                  : 'Today 00:00'}
              </div>
            </div>

            {task.location_name && (
              <div style={{ marginTop: 12 }}>
                <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: 4 }}>LOCATION</div>
                <div style={{
                  background: '#f1f5f0', borderRadius: 8, padding: '10px 12px',
                  fontSize: 14, fontWeight: 500
                }}>
                  📍 {task.location_name}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Actions */}
        {isOwner && task.status === 'in_progress' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginTop: 24 }}>
            <button className="btn-primary" onClick={handleComplete} disabled={completing}>
              {completing ? 'Завершаем...' : '✅ Mark as Completed'}
            </button>
            <button className="btn-secondary" onClick={() => navigate(`/chat/${id}`)}>
              💬 Message Helper
            </button>
          </div>
        )}

        {!isOwner && task.status === 'in_progress' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginTop: 24 }}>
            <button className="btn-secondary" onClick={() => navigate(`/chat/${id}`)}>
              💬 Message Customer
            </button>
          </div>
        )}

        {task.status === 'completed' && !isOwner && (
          <div style={{
            textAlign: 'center', padding: 20,
            background: 'var(--green-pale)', borderRadius: 14,
            color: 'var(--green)', fontWeight: 700, fontSize: 16
          }}>
            ✅ Задача завершена!
          </div>
        )}
      </div>
    </div>
  );
}
